default config for the instance\n *\n * @returns {Axios} A new instance of Axios\n */\nfunction createInstance(defaultConfig) {\n  const context = new Axios(defaultConfig);\n  const instance = bind(Axios.prototype.request, context);\n\n  // Copy axios.prototype to instance\n  utils.extend(instance, Axios.prototype, context, { allOwnKeys: true });\n\n  // Copy context to instance\n  utils.extend(instance, context, null, { allOwnKeys: true });\n\n  // Factory for creating new instances\n  instance.create = function create(instanceConfig) {\n    return createInstance(mergeConfig(defaultConfig, instanceConfig));\n  };\n\n  return instance;\n}\n\n// Create the default instance to be exported\nconst axios = createInstance(defaults);\n\n// Expose Axios class to allow class inheritance\naxios.Axios = Axios;\n\n// Expose Cancel & CancelToken\naxios.CanceledError = CanceledError;\naxios.CancelToken = CancelToken;\naxios.isCancel = isCancel;\naxios.VERSION = VERSION;\naxios.toFormData = toFormData;\n\n// Expose AxiosError class\naxios.AxiosError = AxiosError;\n\n// alias for CanceledError for backward compatibility\naxios.Cancel = axios.CanceledError;\n\n// Expose all/spread\naxios.all = function all(promises) {\n  return Promise.all(promises);\n};\n\naxios.spread = spread;\n\n// Expose isAxiosError\naxios.isAxiosError = isAxiosError;\n\n// Expose mergeConfig\naxios.mergeConfig = mergeConfig;\n\naxios.AxiosHeaders = AxiosHeaders;\n\naxios.formToJSON = (thing) => formDataToJSON(utils.isHTMLForm(thing) ? new FormData(thing) : thing);\n\naxios.getAdapter = adapters.getAdapter;\n\naxios.HttpStatusCode = HttpStatusCode;\n\naxios.default = axios;\n\n// this module should only have a default export\nexport default axios;\n","'use strict';\n\n/**\n * Syntactic sugar for invoking a function and expanding an array for arguments.\n *\n * Common use case would be to use `Function.prototype.apply`.\n *\n *  ```js\n *  function f(x, y, z) {}\n *  const args = [1, 2, 3];\n *  f.apply(null, args);\n *  ```\n *\n * With `spread` this example can be re-written.\n *\n *  ```js\n *  spread(function(x, y, z) {})([1, 2, 3]);\n *  ```\n *\n * @param {Function} callback\n *\n * @returns {Function}\n */\nexport default function spread(callback) {\n  return function wrap(arr) {\n    return callback.apply(null, arr);\n  };\n}\n","'use strict';\n\nimport utils from '../utils.js';\n\n/**\n * Determines whether the payload is an error thrown by Axios\n *\n * @param {*} payload The value to test\n *\n * @returns {boolean} True if the payload is an error thrown by Axios, otherwise false\n */\nexport default function isAxiosError(payload) {\n  return utils.isObject(payload) && payload.isAxiosError === true;\n}\n","import axios from 'axios';\r\n\r\nconst API_BASE_URL = 'http://localhost:8000';\r\n\r\nconst api = axios.create({\r\n  baseURL: API_BASE_URL,\r\n  headers: {\r\n    'Content-Type': 'application/json',\r\n  },\r\n});\r\n\r\nexport const predictSimple = async (data) => {\r\n  try {\r\n    const response = await api.post('/predict/simple', data);\r\n    return response.data;\r\n  } catch (error) {\r\n    throw error.response?.data || error.message;\r\n  }\r\n};\r\n\r\nexport const predictDaily = async (data) => {\r\n  try {\r\n    const response = await api.post('/predict/daily', data);\r\n    return response.data;\r\n  } catch (error) {\r\n    throw error.response?.data || error.message;\r\n  }\r\n};\r\n\r\nexport const compareScenarios = async (scenario1, scenario2) => {\r\n  try {\r\n    const response = await api.post('/compare', null, {\r\n      params: { scenario_1: scenario1, scenario_2: scenario2 }\r\n    });\r\n    return response.data;\r\n  } catch (error) {\r\n    throw error.response?.data || error.message;\r\n  }\r\n};\r\n\r\nexport const getModelInfo = async () => {\r\n  try {\r\n    const response = await api.get('/model/info');\r\n    return response.data;\r\n  } catch (error) {\r\n    throw error.response?.data || error.message;\r\n  }\r\n};\r\n\r\nexport const healthCheck = async () => {\r\n  try {\r\n    const response = await api.get('/health');\r\n    return response.data;\r\n  } catch (error) {\r\n    throw error.response?.data || error.message;\r\n  }\r\n};","const STORAGE_KEY = 'prediction_history';\r\n\r\nexport const saveToHistory = (prediction) => {\r\n  const history = getHistory();\r\n  const newEntry = {\r\n    id: Date.now(),\r\n    timestamp: new Date().toISOString(),\r\n    ...prediction\r\n  };\r\n  history.unshift(newEntry);\r\n  // Keep only last 50 predictions\r\n  const trimmed = history.slice(0, 50);\r\n  localStorage.setItem(STORAGE_KEY, JSON.stringify(trimmed));\r\n  return newEntry;\r\n};\r\n\r\nexport const getHistory = () => {\r\n  const data = localStorage.getItem(STORAGE_KEY);\r\n  return data ? JSON.parse(data) : [];\r\n};\r\n\r\nexport const clearHistory = () => {\r\n  localStorage.removeItem(STORAGE_KEY);\r\n};\r\n\r\nexport const deleteFromHistory = (id) => {\r\n  const history = getHistory();\r\n  const filtered = history.filter(item => item.id !== id);\r\n  localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));\r\n};","import React, { useState, useEffect } from 'react';\r\nimport { useNavigate } from 'react-router-dom';\r\nimport PredictionForm from '../components/PredictionForm';\r\nimport ResultCard from '../components/ResultCard';\r\nimport LoadingSpinner from '../components/LoadingSpinner';\r\nimport ErrorAlert from '../components/ErrorAlert';\r\nimport { predictSimple } from '../services/api';\r\nimport { saveToHistory } from '../utils/storage';\r\nimport './Home.css';\r\n\r\nfunction Home() {\r\n  const navigate = useNavigate();\r\n  const [formData, setFormData] = useState({\r\n    property_type: 'Home',\r\n    property_size: 'Medium',\r\n    people_count: 4,\r\n    ac_usage: 'Medium',\r\n    lighting_usage: 'Low',\r\n    weather_condition: 'Normal',\r\n    hour: new Date().getHours(),\r\n    day_of_week: new Date().getDay(),\r\n    holiday: 0,\r\n    day: new Date().getDate(),\r\n    month: new Date().getMonth() + 1\r\n  });\r\n  \r\n  const [prediction, setPrediction] = useState(null);\r\n  const [loading, setLoading] = useState(false);\r\n  const [error, setError] = useState(null);\r\n\r\n  const handleFormChange = (name, value) => {\r\n    setFormData(prev => ({ ...prev, [name]: value }));\r\n  };\r\n\r\n  const handleSubmit = async (e) => {\r\n    e.preventDefault();\r\n    setLoading(true);\r\n    setError(null);\r\n    \r\n    try {\r\n      const result = await predictSimple(formData);\r\n      setPrediction(result);\r\n      saveToHistory(result);\r\n    } catch (err) {\r\n      setError(err.detail || 'Prediction failed');\r\n    } finally {\r\n      setLoading(false);\r\n    }\r\n  };\r\n\r\n  return (\r\n    <div className=\"home-page\">\r\n      <div className=\"hero-section\">\r\n        <h1>Smart Energy Consumption Forecasting</h1>\r\n        <p>Predict, Compare, and Optimize Your Energy Usage</p>\r\n      </div>\r\n\r\n      <div className=\"stats-grid\">\r\n        <div className=\"stat-card\">\r\n          <div className=\"stat-icon\"></div>\r\n          <div className=\"stat-content\">\r\n            <div className=\"stat-label\">Today's Prediction</div>\r\n            <div className=\"stat-value\">\r\n              {prediction ? `${prediction.daily_consumption_kwh} kWh` : '--'}\r\n            </div>\r\n          </div>\r\n        </div>\r\n        \r\n        <div className=\"stat-card\">\r\n          <div className=\"stat-icon\"></div>\r\n          <div className=\"stat-content\">\r\n            <div className=\"stat-label\">This Month</div>\r\n            <div className=\"stat-value\">\r\n              {prediction ? `${prediction.monthly_consumption_kwh} kWh` : '--'}\r\n            </div>\r\n          </div>\r\n        </div>\r\n        \r\n        <div className=\"stat-card\">\r\n          <div className=\"stat-icon\"></div>\r\n          <div className=\"stat-content\">\r\n            <div className=\"stat-label\">Avg Cost/Day</div>\r\n            <div className=\"stat-value\">\r\n              {prediction ? `₹${prediction.daily_cost_inr}` : '--'}\r\n            </div>\r\n          </div>\r\n        </div>\r\n        \r\n        <div className=\"stat-card\">\r\n          <div className=\"stat-icon\"></div>\r\n          <div className=\"stat-content\">\r\n            <div className=\"stat-label\">Usage Category</div>\r\n            <div className=\"stat-value\">\r\n              {prediction ? prediction.usage_category : '--'}\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div className=\"content-grid\">\r\n        <div className=\"form-container\">\r\n          <PredictionForm\r\n            formData={formData}\r\n            onChange={handleFormChange}\r\n            onSubmit={handleSubmit}\r\n            isLoading={loading}\r\n          />\r\n        </div>\r\n        \r\n        <div className=\"results-container\">\r\n          {loading && <LoadingSpinner />}\r\n          {error && <ErrorAlert message={error} onRetry={handleSubmit} />}\r\n          {prediction && !loading && <ResultCard prediction={prediction} />}\r\n        </div>\r\n      </div>\r\n\r\n      <div className=\"action-buttons\">\r\n        <button onClick={() => navigate('/daily-forecast')} className=\"action-btn\">\r\n          View Daily Forecast\r\n        </button>\r\n        <button onClick={() => navigate('/compare')} className=\"action-btn\">\r\n          Compare Scenarios\r\n        </button>\r\n        <button onClick={() => navigate('/history')} className=\"action-btn\">\r\n          View History\r\n        </button>\r\n      </div>\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default Home;","import React, { useState } from 'react';\r\nimport PredictionForm from '../components/PredictionForm';\r\nimport ResultCard from '../components/ResultCard';\r\nimport LoadingSpinner from '../components/LoadingSpinner';\r\nimport ErrorAlert from '../compon