um',\r\n    people_count: 4,\r\n    ac_usage: 'Medium',\r\n    lighting_usage: 'Low',\r\n    weather_condition: 'Normal',\r\n    day_of_week: new Date().getDay(),\r\n    holiday: 0,\r\n    day: new Date().getDate(),\r\n    month: new Date().getMonth() + 1\r\n  });\r\n  \r\n  const [forecast, setForecast] = useState(null);\r\n  const [loading, setLoading] = useState(false);\r\n  const [error, setError] = useState(null);\r\n\r\n  const handleChange = (e) => {\r\n    const { name, value } = e.target;\r\n    setFormData(prev => ({ ...prev, [name]: value }));\r\n  };\r\n\r\n  const handleSubmit = async (e) => {\r\n    e.preventDefault();\r\n    setLoading(true);\r\n    setError(null);\r\n    \r\n    try {\r\n      const result = await predictDaily(formData);\r\n      setForecast(result);\r\n    } catch (err) {\r\n      setError(err.detail || 'Daily forecast failed');\r\n    } finally {\r\n      setLoading(false);\r\n    }\r\n  };\r\n\r\n  const CustomTooltip = ({ active, payload, label }) => {\r\n    if (active && payload && payload.length) {\r\n      return (\r\n        <div className=\"custom-tooltip\">\r\n          <p className=\"tooltip-hour\">Hour: {label}:00</p>\r\n          <p className=\"tooltip-value\">Consumption: {payload[0].value} kWh</p>\r\n          <p className=\"tooltip-cost\">Cost: ₹{payload[0].payload.cost}</p>\r\n          <p className=\"tooltip-period\">Period: {payload[0].payload.time_period}</p>\r\n        </div>\r\n      );\r\n    }\r\n    return null;\r\n  };\r\n\r\n  const getPeakHour = () => {\r\n    if (!forecast) return null;\r\n    const max = Math.max(...forecast.hourly_forecast.map(h => h.consumption_kwh));\r\n    const peak = forecast.hourly_forecast.find(h => h.consumption_kwh === max);\r\n    return peak;\r\n  };\r\n\r\n  const getLowestHour = () => {\r\n    if (!forecast) return null;\r\n    const min = Math.min(...forecast.hourly_forecast.map(h => h.consumption_kwh));\r\n    const lowest = forecast.hourly_forecast.find(h => h.consumption_kwh === min);\r\n    return lowest;\r\n  };\r\n\r\n  const peakHour = getPeakHour();\r\n  const lowestHour = getLowestHour();\r\n\r\n  return (\r\n    <div className=\"daily-forecast-page\">\r\n      <div className=\"page-header\">\r\n        <h1>24-Hour Energy Forecast</h1>\r\n        <p>See how your energy consumption varies throughout the day</p>\r\n      </div>\r\n\r\n      <div className=\"forecast-form-container\">\r\n        <form onSubmit={handleSubmit} className=\"forecast-form\">\r\n          <div className=\"form-row\">\r\n            <div className=\"form-group\">\r\n              <label>Property Type</label>\r\n              <select name=\"property_type\" value={formData.property_type} onChange={handleChange}>\r\n                <option value=\"Home\">Home</option>\r\n                <option value=\"Commercial\">Commercial</option>\r\n              </select>\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>Property Size</label>\r\n              <select name=\"property_size\" value={formData.property_size} onChange={handleChange}>\r\n                <option value=\"Small\">Small</option>\r\n                <option value=\"Medium\">Medium</option>\r\n                <option value=\"Large\">Large</option>\r\n              </select>\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>People Count</label>\r\n              <input type=\"number\" name=\"people_count\" value={formData.people_count} onChange={handleChange} min=\"1\" />\r\n            </div>\r\n          </div>\r\n\r\n          <div className=\"form-row\">\r\n            <div className=\"form-group\">\r\n              <label>AC Usage</label>\r\n              <select name=\"ac_usage\" value={formData.ac_usage} onChange={handleChange}>\r\n                <option value=\"Low\">Low</option>\r\n                <option value=\"Medium\">Medium</option>\r\n                <option value=\"High\">High</option>\r\n              </select>\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>Lighting Usage</label>\r\n              <select name=\"lighting_usage\" value={formData.lighting_usage} onChange={handleChange}>\r\n                <option value=\"Low\">Low</option>\r\n                <option value=\"Medium\">Medium</option>\r\n                <option value=\"High\">High</option>\r\n              </select>\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>Weather</label>\r\n              <select name=\"weather_condition\" value={formData.weather_condition} onChange={handleChange}>\r\n                <option value=\"Cool\">Cool</option>\r\n                <option value=\"Normal\">Normal</option>\r\n                <option value=\"Hot\">Hot</option>\r\n              </select>\r\n            </div>\r\n          </div>\r\n\r\n          <div className=\"form-row\">\r\n            <div className=\"form-group\">\r\n              <label>Day of Week</label>\r\n              <input type=\"number\" name=\"day_of_week\" value={formData.day_of_week} onChange={handleChange} min=\"0\" max=\"6\" />\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>Holiday</label>\r\n              <select name=\"holiday\" value={formData.holiday} onChange={handleChange}>\r\n                <option value=\"0\">No</option>\r\n                <option value=\"1\">Yes</option>\r\n              </select>\r\n            </div>\r\n\r\n            <div className=\"form-group\">\r\n              <label>Date</label>\r\n              <div className=\"date-group\">\r\n                <input type=\"number\" name=\"day\" value={formData.day} onChange={handleChange} min=\"1\" max=\"31\" placeholder=\"Day\" />\r\n                <input type=\"number\" name=\"month\" value={formData.month} onChange={handleChange} min=\"1\" max=\"12\" placeholder=\"Month\" />\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <button type=\"submit\" disabled={loading} className=\"generate-btn\">\r\n            {loading ? 'Generating...' : 'Generate 24-Hour Forecast'}\r\n          </button>\r\n        </form>\r\n      </div>\r\n\r\n      {error && <ErrorAlert message={error} onRetry={handleSubmit} />}\r\n\r\n      {loading && <LoadingSpinner />}\r\n\r\n      {forecast && !loading && (\r\n        <div className=\"forecast-results\">\r\n          <div className=\"summary-cards\">\r\n            <div className=\"summary-card\">\r\n              <div className=\"summary-icon\"></div>\r\n              <div className=\"summary-content\">\r\n                <div className=\"summary-label\">Daily Total</div>\r\n                <div className=\"summary-value\">{forecast.daily_total_kwh} kWh</div>\r\n              </div>\r\n            </div>\r\n            \r\n            <div className=\"summary-card\">\r\n              <div className=\"summary-icon\"></div>\r\n              <div className=\"summary-content\">\r\n                <div className=\"summary-label\">Total Cost</div>\r\n                <div className=\"summary-value\">₹{forecast.daily_total_cost_inr}</div>\r\n              </div>\r\n            </div>\r\n            \r\n            {peakHour && (\r\n              <div className=\"summary-card\">\r\n                <div className=\"summary-icon\"></div>\r\n                <div className=\"summary-content\">\r\n                  <div className=\"summary-label\">Peak Hour</div>\r\n                  <div className=\"summary-value\">{peakHour.hour}:00 ({peakHour.consumption_kwh} kWh)</div>\r\n                </div>\r\n              </div>\r\n            )}\r\n            \r\n            {lowestHour && (\r\n              <div className=\"summary-card\">\r\n                <div className=\"summary-icon\"></div>\r\n                <div className=\"summary-content\">\r\n                  <div className=\"summary-label\">Lowest Hour</div>\r\n                  <div className=\"summary-value\">{lowestHour.hour}:00 ({lowestHour.consumption_kwh} kWh)</div>\r\n                </div>\r\n              </div>\r\n            )}\r\n          </div>\r\n\r\n          <div className=\"chart-container\">\r\n            <h3>Hourly Consumption Pattern</h3>\r\n            <ResponsiveContainer width=\"100%\" height={400}>\r\n              <AreaChart data={forecast.hourly_forecast}>\r\n                <CartesianGrid strokeDasharray=\"3 3\" />\r\n                <XAxis dataKey=\"hour\" label={{ value: 'Hour', position: 'bottom' }} />\r\n                <YAxis label={{ value: 'kWh', angle: -90, position: 'left' }} />\r\n                <Tooltip content={<CustomTooltip />} />\r\n                <Area\r\n                  type=\"monotone\"\r\n                  dataKey=\"consumption_kwh\"\r\n                  stroke=\"#667eea\"\r\n                  fill=\"url(#colorGradient)\"\r\n                />\r\n                <defs>\r\n                  <linearGradient id=\"colorGradient\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\r\n                    <stop offset=\"5%\" stopColor=\"#667eea\" stopOpacity={0.8}/>\r\n                    <stop offset=\"95%\" stopColor=\"#667eea\" stopOpacity={0}/>\r\n                  </linearGradient>\r\n                </defs>\r\n              </AreaChart>\r\n            </ResponsiveContainer>\r\n          </div>\r\n\r\n          <div className=\"hourly-table-container\">\r\n            <h3>Hourly Breakdown</h3>\r\n            <div className=\"table-wrapper\">\r\n              <table className=\"hourly-table\">\r\n                <thead>\r\n                  <tr>\r\n                    <th>Hour</th>\r\n                    <th>Time Period</th>\r\n                    <th>Consumption (kWh)</th>\r\n                    <th>Cost (₹)</th>\r\n                  </tr>\r\n                </thead>\r\n                <tbody>\r\n                  {forecast.hourly_forecast.map((hour) => (\r\n                    <tr key={hour.hour} className={hour.consumption_kwh === peakHour?.consumption_kwh ? 'peak-row' : ''}>\r\n                      <td>{hour.hour}:00</td>\r\n                      <td>{hour.time_period}</td>\r\n                      <td>{hour.consumption_kwh}</td>\r\n                      <td>₹{hour.cost_inr}</td>\r\n                    </tr>\r\n                  ))}\r\n                </tbody>\r\n              </table>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      )}\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default DailyForecast;","import React, { useState } from 'react';\r\nimport PredictionForm from '../components/PredictionForm';\r\nimport LoadingSpinner from '../components/LoadingSpinner';\r\nimport ErrorAlert from '../components/ErrorAlert';\r\nimport { predictSimple } from '../services/api';\r\nimport './Compare.css';\r\n\r\nfunction Compare() {\r\n  const [scenario1, setScenario1] = useState({\r\n    property_type: 'Home',\r\n    property_size: 'Medium',\r\n    people_count: 4,\r\n    ac_usage: 'High',\r\n    lighting_usage: 'Low',\r\n    weather_condition: 'Hot',\r\n    hour: 14,\r\n    day_of_week: 2,\r\n    holiday: 0,\r\n    day: 15,\r\n    month: 5\r\n  });\r\n  \r\n  const [scenario2, setScenario2] = useState({\r\n    property_type: 'Home',\r\n    property_size: 'Medium',\r\n    people_count: 4,\r\n    ac_usage: 'Low',\r\n    lighting_usage: 'Low',\r\n    weather_condition: 'Hot',\r\n    hour: 14,\r\n    day_of_week: 2,\r\n    holiday: 0,\r\n    day: 15,\r\n    month: 5\r\n  });\r\n  \r\n  const [comparison, setComparison] = useState(null);\r\n  const [loading1, setLoading1] = useState(false);\r\n  const [loading2, setLoading2] = useState(false);\r\n  const [error, setError] = useState(null);\r\n\r\n  const handleScenario1Change = (name, value) => {\r\n    setScenario1(prev => ({ ...prev, [name]: value }));\r\n  };\r\n\r\n  const handleScenario2Change = (name, value) => {\r\n    setScenario2(prev => ({ ...prev, [name]: value }));\r\n  };\r\n\r\n  const handleCompare = async (e) => {\r\n    e.preventDefault();\r\n    setLoading1(true);\r\n    setLoading2(true);\r\n    setError(null);\r\n    \r\n    try {\r\n      const [pred1, pred2] = await Promise.all([\r\n        predictSimple(scenario1),\r\n        predictSimple(scenario2)\r\n      ]);\r\n      \r\n      const kwhDiff = pred1.daily_consumption_kwh - pred2.daily_consumption_kwh;\r\n      const costDiff = pred1.daily_cost_inr - pred2.daily_cost_inr;\r\n      const percentDiff = (kwhDiff / pred1.daily_consumption_kwh) * 100;\r\n      \r\n      setComparison({\r\n        scenario1: pred1,\r\n        scenario2: pred2,\r\n        kwhSaved: Math.abs(kwhDiff),\r\n        costSaved: Math.abs(costDiff),\r\n        percentChange: Math.abs(percentDiff),\r\n        winner: kwhDiff > 0 ? 'Scenario 2' : 'Scenario 1',\r\n        message: kwhDiff > 0 \r\n          ? `Scenario 2 saves ${Math.abs(kwhDiff).toFixed(2)} kWh (₹${Math.abs(costDiff).toFixed(2)}) per day`\r\n          : `Scenario 1 saves ${Math.abs(kwhDiff).toFixed(2)} kWh (₹${Math.abs(costDiff).toFixed(2)}) per day`\r\n      });\r\n    } catch (err) {\r\n      setError(err.detail || 'Comparison failed');\r\n    } finally {\r\n      setLoading1(false);\r\n      setLoading2(false);\r\n    }\r\n  };\r\n\r\n  const loadPreset = (preset) => {\r\n    if (preset === 'ac_on_off') {\r\n      setScenario1(prev => ({ ...prev, ac_usage: 'High' }));\r\n      setScenario2(prev => ({ ...prev, ac_usage: 'Low' }));\r\n    } else if (preset === 'peak_offpeak') {\r\n      setScenario1(prev => ({ ...prev, hour: 18 }));\r\n      setScenario2(prev => ({ ...prev, hour: 6 }));\r\n    } else if (preset === 'weekday_weekend') {\r\n      setScenario1(prev => ({ ...prev, day_of_week: 2, holiday: 0 }));\r\n      setScenario2(prev => ({ ...prev, day_of_week: 6, holiday: 1 }));\r\n    }\r\n  };\r\n\r\n  return (\r\n    <div className=\"compare-page\">\r\n      <div className=\"page-header\">\r\n        <h1>Scenario Comparison</h1>\r\n        <p>Compare different usage patterns to find the most efficient option</p>\r\n      </div>\r\n\r\n      <div className=\"presets\">\r\n        <button onClick={() => loadPreset('ac_on_off')} className=\"preset-btn\">\r\n          AC High vs AC Low\r\n        </button>\r\n        <button onClick={() => loadPreset('peak_offpeak')} className=\"preset-btn\">\r\n          Peak Hour vs Off-Peak\r\n        </button>\r\n        <button onClick={() => loadPreset('weekday_weekend')} className=\"preset-btn\">\r\n          Weekday vs Weekend\r\n        </button>\r\n      </div>\r\n\r\n      <form onSubmit={handleCompare} className=\"compare-form\">\r\n        <div className=\"scenarios-container\">\r\n          <div className=\"scenario-card\">\r\n            <h3>Scenario 1</h3>\r\n            <PredictionForm\r\n              formData={scenario1}\r\n              onChange={handleScenario1Change}\r\n              onSubmit={(e) => e.preventDefault()}\r\n              isLoading={loading1}\r\n            />\r\n          </div>\r\n\r\n          <div className=\"vs-divider\">\r\n            <span className=\"vs-badge\">VS</span>\r\n          </div>\r\n\r\n          <div className=\"scenario-card\">\r\n            <h3>Scenario 2</h3>\r\n            <PredictionForm\r\n              formData={scenario2}\r\n              onChange={handleScenario2Change}\r\n              onSubmit={(e) => e.preventDefault()}\r\n              isLoading={loading2}\r\n            />\r\n          </div>\r\n        </div>\r\n\r\n        <button type=\"submit\" disabled={loading1 || loading2} className=\"compare-btn\">\r\n          {loading1 || loading2 ? 'Comparing...' : 'Compare Scenarios'}\r\n        </button>\r\n      </form>\r\n\r\n      {error && <ErrorAlert message={error} onRetry={handleCompare} />}\r\n\r\n      {comparison && !loading1 && !loading2 && (\r\n        <div className=\"comparison-results\">\r\n          <div className=\"winner-banner\">\r\n            Winner: {comparison.winner} is more efficient!\r\n          </div>\r\n\r\n          <div className=\"comparison-grid\">\r\n            <div className=\"comparison-card\">\r\n              <h4>Scenario 1</h4>\r\n              <div className=\"metric\">\r\n                <span>Daily Consumption</span>\r\n                <strong>{comparison.scenario1.daily_consumption_kwh} kWh</strong>\r\n              </div>\r\n              <div className=\"metric\">\r\n                <span>Daily Cost</span>\r\n                <strong>₹{comparison.scenario1.daily_cost_inr}</strong>\r\n              </div>\r\n              <div className=\"metric\">\r\n                <span>Monthly Cost</span>\r\n                <strong>₹{comparison.scenario1.monthly_cost_inr}</strong>\r\n              </div>\r\n              <div className=\"usage-badge\" style={{ backgroundColor: \r\n                comparison.scenario1.usage_category === 'Low' ? '#4caf50' :\r\n                comparison.scenario1.usage_category === 'Moderate' ? '#ff9800' : '#f44336'\r\n              }}>\r\n                {comparison.scenario1.usage_category}\r\n              </div>\r\n            </div>\r\n\r\n            <div className=\"difference-card\">\r\n              <div className=\"difference-value\">\r\n                <span className=\"diff-label\">Difference</span>\r\n                <span className=\"diff-number\">-{comparison.kwhSaved} kWh</span>\r\n                <span className=\"diff-cost\">-₹{comparison.costSaved}/day</span>\r\n                <span className=\"diff-percent\">{comparison.percentChange}% reduction</span>\r\n              </div>\r\n              <div className=\"savings-bar\">\r\n                <div \r\n                  className=\"savings-fill\" \r\n                  style={{ width: `${Math.min(comparison.percentChange, 100)}%` }}\r\n                ></div>\r\n              </div>\r\n              <p className=\"savings-message\">{comparison.message}</p>\r\n            </div>\r\n\r\n            <div className=\"comparison-card\">\r\n              <h4>Scenario 2</h4>\r\n              <div className=\"metric\">\r\n                <span>Daily Consumption</span>\r\n                <strong>{comparison.scenario2.daily_consumption_kwh} kWh</strong>\r\n              </div>\r\n              <div className=\"metric\">\r\n                <span>Daily Cost</span>\r\n                <strong>₹{comparison.scenario2.daily_cost_inr}</strong>\r\n              </div>\r\n              <div className=\"metric\">\r\n                <span>Monthly Cost</span>\r\n                <strong>₹{comparison.scenario2.monthly_cost_inr}</strong>\r\n              </div>\r\n              <div className=\"usage-badge\" style={{ backgroundColor: \r\n                comparison.scenario2.usage_category === 'Low' ? '#4caf50' :\r\n                comparison.scenario2.usage_category === 'Moderate' ? '#ff9800' : '#f44336'\r\n              }}>\r\n                {comparison.scenario2.usage_category}\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div className=\"recommendation-card\">\r\n            <strong>Recommendation</strong>\r\n            <p>{comparison.message}. Choose {comparison.winner} for optimal savings.</p>\r\n          </div>\r\n        </div>\r\n      )}\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default Compare;","import React, { useState, useEffect } from 'react';\r\nimport { getHistory, clearHistory, deleteFromHistory } from '../utils/storage';\r\nimport './History.css';\r\n\r\nfunction History() {\r\n  const [history, setHistory] = useState([]);\r\n  const [filter, setFilter] = useState('all');\r\n\r\n  useEffect(() => {\r\n    loadHistory();\r\n  }, []);\r\n\r\n  const loadHistory = () => {\r\n    const data = getHistory();\r\n    setHistory(data);\r\n  };\r\n\r\n  const handleClearAll = () => {\r\n    if (window.confirm('Are you sure you want to clear all history?')) {\r\n      clearHistory();\r\n      loadHistory();\r\n    }\r\n  };\r\n\r\n  const handleDelete = (id) => {\r\n    if (window.confirm('Delete this prediction?')) {\r\n      deleteFromHistory(id);\r\n      loadHistory();\r\n    }\r\n  };\r\n\r\n  const filteredHistory = history.filter(item => {\r\n    if (filter === 'all') return true;\r\n    return item.usage_category.toLowerCase() === filter.toLowerCase();\r\n  });\r\n\r\n  const stats = {\r\n    total: history.length,\r\n    avgDaily: history.reduce((sum, item) => sum + item.daily_consumption_kwh, 0) / (history.length || 1),\r\n    avgCost: history.reduce((sum, item) => sum + item.daily_cost_inr, 0) / (history.length || 1),\r\n    lowCount: history.filter(item => item.usage_category === 'Low').length,\r\n    moderateCount: history.filter(item => item.usage_category === 'Moderate').length,\r\n    highCount: history.filter(item => item.usage_category === 'High').length\r\n  };\r\n\r\n  return (\r\n    <div className=\"history-page\">\r\n      <div className=\"page-header\">\r\n        <h1>Prediction History</h1>\r\n        <p>View and manage your past predictions</p>\r\n      </div>\r\n\r\n      <div className=\"stats-section\">\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">{stats.total}</div>\r\n          <div className=\"stat-label\">Total Predictions</div>\r\n        </div>\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">{stats.avgDaily.toFixed(1)} kWh</div>\r\n          <div className=\"stat-label\">Avg Daily Usage</div>\r\n        </div>\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">₹{stats.avgCost.toFixed(0)}</div>\r\n          <div className=\"stat-label\">Avg Daily Cost</div>\r\n        </div>\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">{stats.lowCount}</div>\r\n          <div className=\"stat-label\">Low Usage</div>\r\n        </div>\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">{stats.moderateCount}</div>\r\n          <div className=\"stat-label\">Moderate</div>\r\n        </div>\r\n        <div className=\"stat-box\">\r\n          <div className=\"stat-number\">{stats.highCount}</div>\r\n          <div className=\"stat-label\">High Usage</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div className=\"history-controls\">\r\n        <div className=\"filter-buttons\">\r\n          <button \r\n            className={`filter-btn ${filter === 'all' ? 'active' : ''}`}\r\n            onClick={() => setFilter('all')}\r\n          >\r\n            All\r\n          </button>\r\n          <button \r\n            className={`filter-btn ${filter === 'low' ? 'active' : ''}`}\r\n            onClick={() => setFilter('low')}\r\n          >\r\n            Low\r\n          </button>\r\n          <button \r\n            className={`filter-btn ${filter === 'moderate' ? 'active' : ''}`}\r\n            onClick={() => setFilter('moderate')}\r\n          >\r\n            Moderate\r\n          </button>\r\n          <button \r\n            className={`filter-btn ${filter === 'high' ? 'active' : ''}`}\r\n            onClick={() => setFilter('high')}\r\n          >\r\n            High\r\n          </button>\r\n        </div>\r\n        <button onClick={handleClearAll} className=\"clear-btn\">\r\n          Clear All\r\n        </button>\r\n      </div>\r\n\r\n      {filteredHistory.length === 0 ? (\r\n        <div className=\"empty-state\">\r\n          <div className=\"empty-icon\"></div>\r\n          <p>No predictions yet. Make your first prediction!</p>\r\n        </div>\r\n      ) : (\r\n        <div className=\"history-list\">\r\n          {filteredHistory.map((item) => (\r\n            <div key={item.id} className=\"history-card\">\r\n              <div className=\"history-header\">\r\n                <span className=\"history-date\">\r\n                  {new Date(item.timestamp).toLocaleString()}\r\n                </span>\r\n                <button \r\n                  onClick={() => handleDelete(item.id)}\r\n                  className=\"delete-btn\"\r\n                >\r\n                  ×\r\n                </button>\r\n              </div>\r\n              <div className=\"history-body\">\r\n                <div className=\"history-property\">\r\n                  <span className=\"badge\">{item.property_type}</span>\r\n                  <span className=\"badge\">{item.usage_category}</span>\r\n                </div>\r\n                <div className=\"history-stats\">\r\n                  <div>\r\n                    <span>Daily:</span>\r\n                    <strong>{item.daily_consumption_kwh} kWh</strong>\r\n                  </div>\r\n                  <div>\r\n                    <span>Cost:</span>\r\n                    <strong>₹{item.daily_cost_inr}</strong>\r\n                  </div>\r\n                  <div>\r\n                    <span>Monthly:</span>\r\n                    <strong>₹{item.monthly_cost_inr}</strong>\r\n                  </div>\r\n                </div>\r\n                <div className=\"history-recommendation\">\r\n                  {item.recommendation.substring(0, 100)}...\r\n                </div>\r\n              </div>\r\n            </div>\r\n          ))}\r\n        </div>\r\n      )}\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default History;","import React, { useState, useEffect } from 'react';\r\nimport { getModelInfo } from '../services/api';\r\nimport './About.css';\r\n\r\nfunction About() {\r\n  const [modelInfo, setModelInfo] = useState(null);\r\n  const [loading, setLoading] = useState(true);\r\n\r\n  useEffect(() => {\r\n    fetchModelInfo();\r\n  }, []);\r\n\r\n  const fetchModelInfo = async () => {\r\n    try {\r\n      const info = await getModelInfo();\r\n      setModelInfo(info);\r\n    } catch (error) {\r\n      console.error('Failed to fetch model info:', error);\r\n    } finally {\r\n      setLoading(false);\r\n    }\r\n  };\r\n\r\n  return (\r\n    <div className=\"about-page\">\r\n      <div className=\"page-header\">\r\n        <h1>About This Tool</h1>\r\n        <p>Learn how our energy consumption forecasting system works</p>\r\n      </div>\r\n\r\n      <div className=\"about-grid\">\r\n        <div className=\"about-card\">\r\n          <h3>How It Works</h3>\r\n          <p>Our system uses machine learning to predict energy consumption based on multiple factors:</p>\r\n          <ul>\r\n            <li>Building characteristics (size, type, occupancy)</li>\r\n            <li>Usage patterns (AC, lighting)</li>\r\n            <li>Environmental conditions (temperature, humidity)</li>\r\n            <li>Temporal factors (hour, day, month, holidays)</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div className=\"about-card\">\r\n          <h3>Model Details</h3>\r\n          {loading ? (\r\n            <p>Loading model information...</p>\r\n          ) : modelInfo ? (\r\n            <>\r\n              <p><strong>Model Type:</strong> {modelInfo.model_type}</p>\r\n              <p><strong>Features:</strong> {modelInfo.feature_count} parameters</p>\r\n              <p><strong>Status:</strong> {modelInfo.model_loaded ? 'Active' : 'Using fallback'}</p>\r\n            </>\r\n          ) : (\r\n            <p>Model information unavailable</p>\r\n          )}\r\n        </div>\r\n\r\n        <div className=\"about-card\">\r\n          <h3>Pricing Information</h3>\r\n          <p>Electricity rates used for cost calculations:</p>\r\n          <ul>\r\n            <li><strong>Domestic (Home):</strong> ₹6.5 per kWh</li>\r\n            <li><strong>Commercial:</strong> ₹9.0 per kWh</li>\r\n          </ul>\r\n          <p className=\"note\">*Based on average Indian electricity tariffs</p>\r\n        </div>\r\n\r\n        <div className=\"about-card\">\r\n          <h3>Tips for Best Results</h3>\r\n          <ul>\r\n            <li>Select the correct property size for your building</li>\r\n            <li>Be honest about AC and lighting usage patterns</li>\r\n            <li>Consider seasonal variations in weather</li>\r\n            <li>Use scenario comparison for \"what-if\" analysis</li>\r\n          </ul>\r\n        </div>\r\n\r\n        <div className=\"about-card\">\r\n          <h3>Features Used</h3>\r\n          <div className=\"features-grid\">\r\n            <span className=\"feature-tag\">Temperature</span>\r\n            <span className=\"feature-tag\">Humidity</span>\r\n            <span className=\"feature-tag\">Square Footage</span>\r\n            <span className=\"feature-tag\">Occupancy</span>\r\n            <span className=\"feature-tag\">HVAC Usage</span>\r\n            <span className=\"feature-tag\">Lighting Usage</span>\r\n            <span className=\"feature-tag\">Day of Week</span>\r\n            <span className=\"feature-tag\">Holiday</span>\r\n            <span className=\"feature-tag\">Hour</span>\r\n            <span className=\"feature-tag\">Day</span>\r\n            <span className=\"feature-tag\">Month</span>\r\n          </div>\r\n        </div>\r\n\r\n        <div className=\"about-card\">\r\n          <h3>Tech Stack</h3>\r\n          <ul>\r\n            <li><strong>Backend:</strong> FastAPI, Python, scikit-learn</li>\r\n            <li><strong>Frontend:</strong> React, Axios, Recharts</li>\r\n            <li><strong>Model:</strong> Random Forest Regressor</li>\r\n          </ul>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default About;","import React from 'react';\nimport { BrowserRouter as Router, Routes, Route } from 'react-router-dom';\nimport Navbar from './components/Navbar';\nimport Home from './pages/Home';\nimport Predict from './pages/Predict';\nimport DailyForecast from './pages/DailyForecast';\nimport Compare from './pages/Compare';\nimport History from './pages/History';\nimport About from './pages/About';\nimport './App.css';\n\nfunction App() {\n  return (\n    <Router>\n      <div className=\"App\">\n        <Navbar />\n        <main className=\"main-content\">\n          <Routes>\n            <Route path=\"/\" element={<Home />} />\n            <Route path=\"/predict\" element={<Predict />} />\n            <Route path=\"/daily-forecast\" element={<DailyForecast />} />\n            <Route path=\"/compare\" element={<Compare />} />\n            <Route path=\"/history\" element={<History />} />\n            <Route path=\"/about\" element={<About />} />\n          </Routes>\n        </main>\n      </div>\n    </Router>\n  );\n}\n\nexport default App;","import React from 'react';\r\nimport ReactDOM from 'react-dom/client';\r\nimport './index.css';\r\nimport App from './App';\r\n\r\nconst root = ReactDOM.createRoot(document.getElementById('root'));\r\nroot.render(\r\n  <React.StrictMode>\r\n    <App />\r\n  </React.StrictMode>\r\n);"],"names":["__WEBPACK_AMD_DEFINE_RESULT__","ONE","MAX_DIGITS","Decimal","precision","rounding","toExpNeg","toExpPos","LN10","external","decimalError","invalidArgument","exponentOutOfRange","mathfloor","Math","floor","mathpow","pow","isDecimal","BASE","MAX_SAFE_INTEGER","MAX_E","P","add","x","y","carry","d","e","i","k","len","xd","yd","Ctor","constructor","pr","s","round","slice","length","ceil","reverse","push","unshift","pop","checkInt32","min","max","Error","digitsToString","ws","indexOfLastWord","str","w","getZeroString","absoluteValue","abs","this","comparedTo","cmp","j","xdL","ydL","decimalPlaces","dp","dividedBy","div","divide","dividedToIntegerBy","idiv","equals","eq","exponent","getBase10Exponent","greaterThan","gt","greaterThanOrEqualTo","gte","isInteger","isint","isNegative","isneg","isPositive","ispos","isZero","lessThan","lt","lessThanOrEqualTo","lte","logarithm","log","base","r","wpr","ln","minus","sub","subtract","modulo","mod","q","times","naturalExponential","exp","naturalLogarithm","negated","neg","plus","sd","z","squareRoot","sqrt","n","t","toExponential","indexOf","toString","mul","rL","shift","toDecimalPlaces","todp","rm","toFixed","toInteger","toint","toNumber","toPower","sign"